const raw = $json.text ?? $json.output ?? $json.response ?? "";

if (!raw) {
  throw new Error("Final Answer Maker returned no text");
}

let parsed;
try {
  parsed = JSON.parse(raw);
} catch (e) {
  throw new Error("Final Answer output is not valid JSON: " + raw);
}

return [{ json: parsed }];

const latestCheck = $input.first().json;

// Pull messages from Get Thread Messages 2
const rawNode = $node["Get Thread Messages 2"].json;

// Support either shape:
// A) { thread_id: 10, messages: [...] }
// B) [ { thread_id: 10, messages: [...] } ]
let messages = [];

if (Array.isArray(rawNode)) {
  messages = rawNode[0]?.messages ?? [];
} else {
  messages = rawNode.messages ?? [];
}

const currentWaMessageId = latestCheck.current_execution_message || null;

// Sort by timestamp ascending just in case
messages = [...messages].sort((a, b) => {
  return new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime();
});

// Find current inbound message
const currentMsg = messages.find(m => m.wa_message_id === currentWaMessageId);

// Fallback: latest inbound message
const latestInbound = [...messages].reverse().find(m => m.direction === "in");

// Use current matched message if found, otherwise fallback
const anchorMsg = currentMsg || latestInbound || null;

const anchorTimestamp = anchorMsg?.timestamp
  ? new Date(anchorMsg.timestamp).getTime()
  : Date.now();

// Keep recent messages within 20 minutes before anchor
const WINDOW_MS = 20 * 60 * 1000;

const recentWindow = messages.filter(m => {
  if (!m.timestamp) return false;
  const ts = new Date(m.timestamp).getTime();
  return ts <= anchorTimestamp && (anchorTimestamp - ts) <= WINDOW_MS;
});

// Recent inbound user messages only
const recentInbound = recentWindow
  .filter(m => m.direction === "in" && typeof m.text === "string" && m.text.trim() !== "")
  .slice(-6);

// Recent outbound bot messages only
const recentOutbound = recentWindow
  .filter(m => m.direction === "out" && typeof m.text === "string" && m.text.trim() !== "")
  .slice(-3);

// Latest user message
const latestUserMessage = anchorMsg?.direction === "in"
  ? (anchorMsg.text || "").trim()
  : (latestInbound?.text || "").trim();

// Last outbound reply
const lastOutboundReply = recentOutbound.length
  ? recentOutbound[recentOutbound.length - 1].text.trim()
  : null;

// Array of recent user messages
const recentUserMessages = recentInbound.map(m => m.text.trim());

// Compact conversation context
const conversationContext = [
  recentInbound.length
    ? `Recent user messages: ${recentInbound.map(m => `"${m.text.trim()}"`).join(" | ")}`
    : null,
  lastOutboundReply
    ? `Last outbound reply: "${lastOutboundReply}"`
    : null
].filter(Boolean).join("\n");

return [
  {
    json: {
      latest_after_wait: latestCheck.latest_after_wait ?? null,
      current_execution_message: latestCheck.current_execution_message ?? null,
      current_wa_message_id: currentWaMessageId,
      latest_user_message: latestUserMessage || null,
      recent_user_messages: recentUserMessages,
      last_outbound_reply: lastOutboundReply,
      conversation_context: conversationContext,
      conversation_message_count: recentInbound.length
    }
  }
];

const raw = $input.all();

if (!raw || raw.length === 0) {
  return [
    {
      json: {
        candidates: []
      }
    }
  ];
}

// If the HTTP node already emitted candidate items one by one
return [
  {
    json: {
      candidates: raw.map(item => item.json)
    }
  }
];

