const state = $node["Refresh Thread State"].json;
const candidatesNode = $node["Normalize Thread Candidates"].json;

const candidates = candidatesNode.candidates || [];
const focusId = state.current_focus_candidate_id;

let focusCandidate = null;

if (focusId != null) {
  focusCandidate = candidates.find(c => c.id === focusId) || null;
}

// fallback: if no focus id, try candidate with current_focus
if (!focusCandidate) {
  focusCandidate = candidates.find(c => c.status === "current_focus") || null;
}

if (!focusCandidate) {
  return [
    {
      json: {
        effective_state: null,
        ready_for_price: false,
        missing_fields: ["candidate"]
      }
    }
  ];
}

const normalize = (value) =>
