let effectiveZoneGroup = focusCandidate.zone_group ?? null;
const effectiveZoneDetail = focusCandidate.zone_detail ?? null;

// if zone_group is missing but zone_detail is known, try to infer it
if (!effectiveZoneGroup && effectiveZoneDetail) {
  effectiveZoneGroup = inferZoneGroupFromDetail(effectiveZoneDetail);
}

const missing = [];
if (!focusCandidate.tipo_vehiculo) missing.push("tipo_vehiculo");

// only ask for location if zone_detail itself is missing.
// if zone_detail exists, do not mark location as missing just because zone_group is null.
if (!effectiveZoneDetail) {
  missing.push("zone_detail");
}

return [
  {
    json: {
      effective_state: {
        tipo_vehiculo: focusCandidate.tipo_vehiculo ?? null,
        zone_group: effectiveZoneGroup,
        zone_detail: effectiveZoneDetail,
        marca: focusCandidate.marca ?? null,
        modelo: focusCandidate.modelo ?? null,
        anio: focusCandidate.anio ?? null,
        candidate_id: focusCandidate.id
      },
      ready_for_price: missing.length === 0 && !!effectiveZoneGroup,
      missing_fields: missing
    }
  }
];

const current_execution_message = $node["Webhook"].json["body"]["wa_message_id"];

// Read Get Thread Messages 2 output
const raw = $node["Get Thread Messages 2"].json;

let messages = [];

if (Array.isArray(raw)) {
  if (raw.length > 0 && raw[0].messages) {
    messages = raw[0].messages;
  } else {
    messages = raw;
  }
} else if (raw.messages) {
  messages = raw.messages;
}

// Keep only inbound user messages
const inboundMessages = messages.filter(
  m => m.direction === "in" && m.wa_message_id
);

// Sort oldest → newest
inboundMessages.sort((a, b) => {
  return new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime();
});

const latestInbound = inboundMessages.length
  ? inboundMessages[inboundMessages.length - 1].wa_message_id
  : null;

return [
  {
    json: {
      latest_after_wait: latestInbound,
      current_execution_message
    }
  }
];

const crm = $node["Parser Updater Output"].json.crm_mirror || {};

const ESTADO_MAP = {
  "Consulta nueva": "CONSULTA_NUEVA",
  "Coordinar disponibilidad": "COORDINAR_DISPONIBILIDAD",
  "Agendado": "AGENDADO",
  "Revisión completa": "REVISION_COMPLETA",
  "Atención humana": "ATENCION_HUMANA",

  CONSULTA_NUEVA: "CONSULTA_NUEVA",
  COORDINAR_DISPONIBILIDAD: "COORDINAR_DISPONIBILIDAD",
  AGENDADO: "AGENDADO",
  REVISION_COMPLETA: "REVISION_COMPLETA",
  ATENCION_HUMANA: "ATENCION_HUMANA",
};

const FLAG_MAP = {
  "Presupuestando": "PRESUPUESTANDO",
  "Presupuesto enviado": "PRESUPUESTO_ENVIADO",
  "Aceptado": "ACEPTADO",
  "Re-compra": "RECOMPRA",
  "Perdido": "PERDIDO",

  PRESUPUESTANDO: "PRESUPUESTANDO",
  PRESUPUESTO_ENVIADO: "PRESUPUESTO_ENVIADO",
  ACEPTADO: "ACEPTADO",
  RECOMPRA: "RECOMPRA",
  PERDIDO: "PERDIDO",
};

const mappedEstado = crm.estado ? ESTADO_MAP[crm.estado] ?? null : null;
const mappedFlag = crm.flag ? FLAG_MAP[crm.flag] ?? null : null;

const patch = {
  estado: mappedEstado,
  flag: mappedFlag,
  necesita_humano: crm.necesita_humano,
};

// only include motivo_perdida when flag is PERDIDO
if (mappedFlag === "PERDIDO" && crm.motivo_perdida) {
  patch.motivo_perdida = crm.motivo_perdida;
}

const clean = Object.fromEntries(
  Object.entries(patch).filter(([, v]) => v !== null && v !== undefined)
);

return [{ json: clean }];

const revisionPatch = $node["Parser Updater Output"].json.lead_revision_patch || {};
const effectiveRevisionId = ($json.effective_revision_id && $json.effective_revision_id !== 0) ? $json.effective_revision_id : null;

const cleanPatch = Object.fromEntries(
  Object.entries(revisionPatch).filter(([, v]) => v !== null && v !== undefined && v !== "")
);

return [
  {
    json: {
      effective_revision_id: effectiveRevisionId,
      revision_patch: cleanPatch
    }
  }
];

const updater = $node["Parser Updater Output"].json;
const bookingSignals = updater.booking_signals || {};
const revPatch = updater.lead_revision_patch || {};

// Parse date
const dayText = (bookingSignals.preferred_day_text || "").toLowerCase().trim();
const today = new Date();
let targetDate = new Date(today);

if (dayText.includes("mañana")) {
  targetDate.setDate(today.getDate() + 1);
} else if (dayText.includes("pasado")) {
  targetDate.setDate(today.getDate() + 2);
} else if (dayText.match(/\d{4}-\d{2}-\d{2}/)) {
  targetDate = new Date(dayText.match(/\d{4}-\d{2}-\d{2}/)[0]);
}

const preferred_day = targetDate.toISOString().split("T")[0];

// Parse time - handles "14hs", "14h", "14:00", "14", "2pm"
const timeRaw = (bookingSignals.preferred_time_text || revPatch.turno_hora || "10:00").toString().trim();
let preferred_time = "10:00";

const match = timeRaw.match(/^(\d{1,2})[\s:hH]?(\d{0,2})/);
if (match) {
  const hours = match[1].padStart(2, "0");
  const minutes = (match[2] && match[2].length === 2) ? match[2] : "00";
  preferred_time = `${hours}:${minutes}`;
}

// Build address
const direccion = revPatch.direccion_texto || "";
const zoneDetail = revPatch.zone_detail || "";
const zoneGroup = revPatch.zone_group || "";
const address = [direccion, zoneDetail, zoneGroup].filter(Boolean).join(", ");

return [{
  json: {
    address: address || "Sin direccion",
    preferred_day,
    preferred_time,
    zone_group: zoneGroup,
    zone_detail: zoneDetail,
    lead_revision_patch: revPatch,
    booking_signals: bookingSignals
  }
}];
